import React from 'react';
import Article from '../Article.js';
import './Head.css';
import { stories } from '../Stories.js';

var temp = stories;

function Head(props) {
  var story = stories[props.head-1];
  return (
    <div className='Head'>

      <Article index={props.head}/>
      <div id='description'>
        <p>{this.story.description} Read more <a href={stories[props.head-1].url}> here &#10063;</a></p>
      </div>

    </div>
  );
}

export default Head;
